const schemaInfo = $.input.schemaHint || 'No schema provided. Use INFORMATION_SCHEMA to discover tables if needed.';

const prompt = `You are a BigQuery SQL expert. Generate a GoogleSQL query to answer the user's question.

USER QUESTION: ${$.input.question}

BIGQUERY PROJECT: ${$.input.projectId}
DATASET: ${$.input.datasetId}

SCHEMA INFORMATION:
${schemaInfo}

INSTRUCTIONS:
- Write valid GoogleSQL (NOT legacy SQL)
- Use fully qualified table names: \`${$.input.projectId}.${$.input.datasetId}.table_name\`
- Add a LIMIT clause (max 100 rows) to prevent excessive results
- If schema is not provided, first query INFORMATION_SCHEMA.TABLES and INFORMATION_SCHEMA.COLUMNS
- Keep the query efficient and simple
- Add comments explaining what the query does

Return ONLY valid JSON:
{
  "sql": "<the BigQuery SQL query>",
  "explanation": "<brief explanation of what the query does>",
  "needsSchemaDiscovery": false
}`;

return { prompt };

let raw = $.steps.generateSql.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { sql: raw, explanation: 'Could not parse structured response', needsSchemaDiscovery: false }; }

const resp = $.steps.runQuery.response || {};
const schema = resp.schema || {};
const rows = resp.rows || [];
const totalRows = resp.totalRows || rows.length;
const jobComplete = resp.jobComplete;
const fields = (schema.fields || []).map(f => f.name);

// Convert BigQuery row format to readable table
let tableText = '';
if (fields.length > 0) {
  tableText += 'Columns: ' + fields.join(' | ') + '\n';
  tableText += '-'.repeat(50) + '\n';
  rows.slice(0, 50).forEach(row => {
    const values = (row.f || []).map(cell => cell.v || 'null');
    tableText += values.join(' | ') + '\n';
  });
}

const querySql = $.steps.parseSql.output.sql;
const queryExplanation = $.steps.parseSql.output.explanation;

return { tableText, fields, rowCount: rows.length, totalRows, jobComplete, querySql, queryExplanation };

const prompt = `You are a data analyst. Summarize the following database query results in plain language to answer the user's original question.

ORIGINAL QUESTION: ${$.input.question}

SQL QUERY EXECUTED:
${$.steps.formatResults.output.querySql}

QUERY EXPLANATION: ${$.steps.formatResults.output.queryExplanation}

QUERY RESULTS (${$.steps.formatResults.output.rowCount} rows of ${$.steps.formatResults.output.totalRows} total):
${$.steps.formatResults.output.tableText}

INSTRUCTIONS:
- Directly answer the user's question using the data
- Highlight key numbers, trends, or patterns
- If the results are empty or unexpected, explain why
- Use Slack mrkdwn formatting: *bold* (NOT **bold**), _italic_, > for quotes, numbered lists
- Slack mrkdwn rules: No markdown tables. No # headings.

Return ONLY valid JSON:
{
  "answer": "<plain language answer using Slack mrkdwn>",
  "highlights": ["<key data point 1>", "<key data point 2>"],
  "dataQualityNotes": "<any concerns about the data or query>"
}`;

return { prompt };

let raw = $.steps.summarizeResults.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, highlights: [], dataQualityNotes: '' }; }

const ai = $.steps.parseSummary.output || {};
const question = $.input.question;
const sql = $.steps.formatResults.output.querySql || '';
const rowCount = $.steps.formatResults.output.rowCount;
const totalRows = $.steps.formatResults.output.totalRows;

const blocks = [];

blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Database Query Results' } });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'divider' });

const answerText = (ai.answer || 'No answer generated.').slice(0, 2900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: answerText } });
blocks.push({ type: 'divider' });

if (ai.highlights && ai.highlights.length > 0) {
  let highlights = '*Key Data Points:*\n';
  ai.highlights.forEach((h, i) => { highlights += ':small_blue_diamond: ' + h + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: highlights } });
  blocks.push({ type: 'divider' });
}

// Show the SQL query (truncated)
const sqlPreview = sql.length > 500 ? sql.slice(0, 500) + '...' : sql;
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*SQL Query:*\n```' + sqlPreview + '```' } });

if (ai.dataQualityNotes) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':warning: ' + ai.dataQualityNotes }] });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':bar_chart: Rows returned: *' + rowCount + '* of *' + totalRows + '* total | Dataset: *' + $.input.projectId + '.' + $.input.datasetId + '*' }] });

const fallback = 'Database query results for: ' + question;

return { blocks, fallback };
